import UIKit

// MARK: - Network Configuration

enum ServerEnvironment {
    case api
    case legacy
    
    var baseURL: String {
        switch self {
        case .api:
            return "https://api.example.com"
        case .legacy:
            return "http://legacy.internal"
        }
    }
}

// MARK: - Network Error

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case serverError(Int, String?)
    case connectionError(Error)
    case atsBlocked
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .serverError(let code, let message):
            return "Server error \(code): \(message ?? "Unknown")"
        case .connectionError(let error):
            return "Connection error: \(error.localizedDescription)"
        case .atsBlocked:
            return "Connection blocked by App Transport Security. Check ATS exceptions."
        }
    }
}

// MARK: - API Response Models

struct APIResponse<T: Codable>: Codable {
    let success: Bool
    let data: T?
    let message: String?
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct LegacyRecord: Codable {
    let recordId: String
    let value: String
    let timestamp: String
}

// MARK: - Network Session Configuration

class NetworkSessionManager {
    static let shared = NetworkSessionManager()
    
    lazy var secureSession: URLSession = {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.waitsForConnectivity = true
        return URLSession(configuration: config, delegate: SecureSessionDelegate(), delegateQueue: nil)
    }()
    
    lazy var legacySession: URLSession = {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 60
        config.timeoutIntervalForResource = 120
        config.waitsForConnectivity = true
        return URLSession(configuration: config, delegate: LegacySessionDelegate(), delegateQueue: nil)
    }()
    
    private init() {}
}

// MARK: - Session Delegates

class SecureSessionDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.host == "api.example.com" else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
}

class LegacySessionDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        // Allow connections to legacy.internal (HTTP - insecure, allowed via ATS exception)
        if let serverTrust = challenge.protectionSpace.serverTrust {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

// MARK: - Network Service

class NetworkService {
    static let shared = NetworkService()
    
    private let sessionManager = NetworkSessionManager.shared
    
    private init() {}
    
    // MARK: - Generic Request Method
    
    func request<T: Codable>(
        environment: ServerEnvironment,
        path: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil,
        responseType: T.Type
    ) async throws -> T {
        let urlString = "\(environment.baseURL)\(path)"
        
        guard let url = URL(string: urlString) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let session: URLSession
        switch environment {
        case .api:
            session = sessionManager.secureSession
        case .legacy:
            session = sessionManager.legacySession
        }
        
        do {
            let (data, response) = try await session.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.noData
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                let errorMessage = String(data: data, encoding: .utf8)
                throw NetworkError.serverError(httpResponse.statusCode, errorMessage)
            }
            
            do {
                let decoder = JSONDecoder()
                decoder.keyDecodingStrategy = .convertFromSnakeCase
                let decodedResponse = try decoder.decode(T.self, from: data)
                return decodedResponse
            } catch {
                throw NetworkError.decodingError(error)
            }
        } catch let error as NetworkError {
            throw error
        } catch {
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain &&
                nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection {
                throw NetworkError.atsBlocked
            }
            throw NetworkError.connectionError(error)
        }
    }
    
    // MARK: - API Server Methods (HTTPS)
    
    func fetchUsers() async throws -> APIResponse<[User]> {
        return try await request(
            environment: .api,
            path: "/v1/users",
            responseType: APIResponse<[User]>.self
        )
    }
    
    func fetchUser(id: Int) async throws -> APIResponse<User> {
        return try await request(
            environment: .api,
            path: "/v1/users/\(id)",
            responseType: APIResponse<User>.self
        )
    }
    
    func createUser(name: String, email: String) async throws -> APIResponse<User> {
        let body = try JSONEncoder().encode(["name": name, "email": email])
        return try await request(
            environment: .api,
            path: "/v1/users",
            method: "POST",
            body: body,
            responseType: APIResponse<User>.self
        )
    }
    
    // MARK: - Legacy System Methods (HTTP)
    
    func fetchLegacyRecords() async throws -> [LegacyRecord] {
        return try await request(
            environment: .legacy,
            path: "/records",
            responseType: [LegacyRecord].self
        )
    }
    
    func fetchLegacyRecord(id: String) async throws -> LegacyRecord {
        return try await request(
            environment: .legacy,
            path: "/records/\(id)",
            responseType: LegacyRecord.self
        )
    }
    
    func updateLegacyRecord(id: String, value: String) async throws -> LegacyRecord {
        let body = try JSONEncoder().encode(["value": value])
        return try await request(
            environment: .legacy,
            path: "/records/\(id)",
            method: "PUT",
            body: body,
            responseType: LegacyRecord.self
        )
    }
}

// MARK: - ATS Diagnostics

class ATSDiagnostics {
    static func checkATSConfiguration() {
        guard let infoDict = Bundle.main.infoDictionary,
              let atsDict = infoDict["NSAppTransportSecurity"] as? [String: Any] else {
            print("⚠️ No ATS configuration found in Info.plist")
            return
        }
        
        let arbitraryLoads = atsDict["NSAllowsArbitraryLoads"] as? Bool ?? false
        print("🔒 ATS Configuration:")
        print("   Arbitrary Loads: \(arbitraryLoads ? "ENABLED ⚠️" : "DISABLED ✅")")
        
        if let exceptions = atsDict["NSExceptionDomains"] as? [String: Any] {
            print("   Exception Domains:")
            for (domain, config) in exceptions {
                if let domainConfig = config as? [String: Any] {
                    let allowsInsecure = domainConfig["NSExceptionAllowsInsecureHTTPLoads"] as? Bool ?? false
                    let includesSubdomains = domainConfig["NSIncludesSubdomains"] as? Bool ?? false
                    let forwardSecrecy = domainConfig["NSExceptionRequiresForwardSecrecy"] as? Bool ?? true
                    
                    print("     📍 \(domain)")
                    print("        Allows Insecure HTTP: \(allowsInsecure)")
                    print("        Includes Subdomains: \(includesSubdomains)")
                    print("        Requires Forward Secrecy: \(forwardSecrecy)")
                }
            }
        }
    }
    
    static func testConnectivity(to environment: ServerEnvironment) async -> Bool {
        guard let url = URL(string: environment.baseURL) else { return false }
        
        do {
            let (_, response) = try await URLSession.shared.data(from: url)
            if let httpResponse = response as? HTTPURLResponse {
                print("✅ Connection to \(environment.baseURL) succeeded (HTTP \(httpResponse.statusCode))")
                return true
            }
        } catch {
            let nsError = error as NSError
            if nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection {
                print("❌ Connection to \(environment.baseURL) blocked by ATS")
            } else {
                print("❌ Connection to \(environment.baseURL) failed: \(error.localizedDescription)")
            }
        }
        return false
    }
}

// MARK: - View Model

@MainActor
class MainViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var legacyRecords: [LegacyRecord] = []
    @Published var isLoadingAPI = false
    @Published var isLoadingLegacy = false
    @Published var apiError: String?
    @Published var legacyError: String?
    @Published var statusMessage: String = ""
    
    private let networkService = NetworkService.shared
    
    func loadUsers() {
        isLoadingAPI = true
        apiError = nil
        
        Task {
            do {
                let response = try await networkService.fetchUsers()
                users = response.data ?? []
                statusMessage = "Loaded \(users.count) users from API server (HTTPS)"
            } catch {
                apiError = error.localizedDescription
                statusMessage = "API Error: \(error.localizedDescription)"
            }
            isLoadingAPI = false
        }
    }
    
    func loadLegacyRecords() {
        isLoadingLegacy = true
        legacyError = nil
        
        Task {
            do {
                legacyRecords = try await networkService.fetchLegacyRecords()
                statusMessage = "Loaded \(legacyRecords.count) records from legacy system (HTTP)"
            } catch {
                legacyError = error.localizedDescription
                statusMessage = "Legacy Error: \(error.localizedDescription)"
            }
            isLoadingLegacy = false
        }
    }
    
    func runDiagnostics() {
        ATSDiagnostics.checkATSConfiguration()
        
        Task {
            statusMessage = "Running connectivity diagnostics..."
            let apiOk = await ATSDiagnostics.testConnectivity(to: .api)
            let legacyOk = await ATSDiagnostics.testConnectivity(to: .legacy)
            statusMessage = "API: \(apiOk ? "✅" : "❌") | Legacy: \(legacyOk ? "✅" : "❌")"
        }
    }
}

